import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as n,e as s}from"./app-be253e4c.js";const t={},c=s(`<h1 id="tee命令" tabindex="-1"><a class="header-anchor" href="#tee命令" aria-hidden="true">#</a> tee命令</h1><p><code>tee</code>命令会从标准输入设备读取数据，将其内容输出到标准输出设备，同时保存成文件。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">tee</span> <span class="token punctuation">[</span>OPTION<span class="token punctuation">]</span><span class="token punctuation">..</span>. <span class="token punctuation">[</span>FILE<span class="token punctuation">]</span><span class="token punctuation">..</span>.
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-a, --append</code>: 追加到已有文件的后面，而不是覆盖文件。</li><li><code>-i, --ignore-interrupts</code>: 忽略中断信号。</li><li><code>-p</code>: 诊断写入非管道的错误。</li><li><code>--output-error[=MODE]</code>: 设置写错误时的行为。</li><li><code>--help</code>: 显示帮助信息。</li><li><code>--version</code>: 显示版本信息</li></ul><h2 id="模式" tabindex="-1"><a class="header-anchor" href="#模式" aria-hidden="true">#</a> 模式</h2><ul><li><code>warn</code>: 诊断写入任何输出的错误。</li><li><code>warn-nopipe</code>: 诊断写入任何输出而不是管道的错误。</li><li><code>exit</code>: 当错误写入任何输出时退出。</li><li><code>exit-nopipe</code>: 当写入任何输出（不是管道）时出错时退出。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>将用户输入的数据同时保存到文件<code>file1.txt</code>和<code>file2.txt</code>中，输入文件信息后回车即可得到输出反馈。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">tee</span> file1.txt file2.txt 
</code></pre></div><p>将用户输入的数据追加到<code>file1.txt</code>文件。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">tee</span> <span class="token parameter variable">-a</span> file1.txt  
</code></pre></div><p><code>ls</code>列出当前目录中所有文件扩展名为<code>.txt</code>的所有文件，每行一个文件名，将输出通过管道传输到<code>wc</code>，将行进行计数并输出数字，输出通过管道传输到<code>tee</code>，将输出写入终端，并将信息写入文件<code>count.txt</code>，即写入文件扩展名为<code>.txt</code>的所有文件的数量。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ls</span> <span class="token parameter variable">-1</span> *.txt <span class="token operator">|</span> <span class="token function">wc</span> <span class="token parameter variable">-l</span> <span class="token operator">|</span> <span class="token function">tee</span> count.txt
</code></pre></div>`,15),o=[c];function d(i,l){return a(),n("div",null,o)}const h=e(t,[["render",d],["__file","tee.html.vue"]]);export{h as default};
